// const: cannot be reassigned (use this by default)
const API_URL = 'https://api.example.com';
const MAX_RETRIES = 3;

// let: can be reassigned (use when the value will change)
let currentUser = null;
let retryCount = 0;
currentUser = { name: 'Alice' }; // reassignment is fine
retryCount += 1;

// var: function-scoped, hoisted -- avoid in modern code
// var oldSchool = 'dont use this';

// Primitive types
const name = 'Alice';          // string
const age = 30;                // number
const isActive = true;         // boolean
const nothing = null;          // null (intentional absence)
let something;                 // undefined (not yet assigned)
const uniqueId = Symbol('id'); // symbol
const huge = 9007199254740991n; // bigint

// Reference types
const fruits = ['apple', 'banana', 'cherry']; // array
const user = { name: 'Alice', age: 30 };      // object
const greet = (name) => `Hello, ${name}!`;     // function

// Template literals (backtick strings with interpolation)
const greeting = `Hello, ${name}! You are ${age} years old.`;
const multiLine = `
  This string
  spans multiple
  lines.
`;

// Destructuring
const { name: userName, age: userAge } = user;
const [first, second, ...rest] = fruits;

// Spread operator
const moreFruits = [...fruits, 'date', 'elderberry'];
const updatedUser = { ...user, age: 31 };

// Nullish coalescing and optional chaining
const displayName = user.nickname ?? 'Anonymous'; // ?? returns right side only for null/undefined
const city = user.address?.city; // ?. returns undefined instead of throwing if address is null
